"use client";

import React, { useState, useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import api from '@/lib/api';
import { Shield, Mail, Lock, Eye, EyeOff, Loader2, CheckCircle } from 'lucide-react';

export default function LoginPage() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const onboardingSuccess = searchParams.get('onboarding') === 'success';

    // If already authenticated, redirect to /empresa
    useEffect(() => {
        const token = localStorage.getItem('token');
        if (token) {
            api.defaults.headers.common['Authorization'] = `Bearer ${token}`;
            router.replace('/empresa');
        }
    }, [router]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        try {
            const res = await api.post('/api/auth/login', { email, password });
            const { session, user } = res.data;

            if (!session?.access_token) {
                setError('Resposta inválida do servidor.');
                return;
            }

            // Verify this is a company user
            if (user?.nivel_acesso !== 'empresa') {
                setError('Este portal é exclusivo para empresas credenciadas. Use o painel administrativo para outros acessos.');
                return;
            }

            // Persist session
            localStorage.setItem('token', session.access_token);
            localStorage.setItem('refresh_token', session.refresh_token || '');
            localStorage.setItem('user', JSON.stringify(user));

            // Set default header for future requests
            api.defaults.headers.common['Authorization'] = `Bearer ${session.access_token}`;

            router.push('/empresa');
        } catch (err: any) {
            const msg = err.response?.data?.error || 'Erro ao conectar com o servidor.';
            setError(msg);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-[#050B18] relative overflow-hidden px-4">
            {/* Background effects */}
            <div className="absolute top-[10%] left-[10%] w-[400px] h-[400px] bg-cyan-400/10 rounded-full blur-[120px] pointer-events-none" />
            <div className="absolute bottom-[10%] right-[10%] w-[400px] h-[400px] bg-purple-500/10 rounded-full blur-[120px] pointer-events-none" />
            <div className="absolute inset-0 bg-[linear-gradient(rgba(0,212,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(0,212,255,0.03)_1px,transparent_1px)] bg-[size:50px_50px] pointer-events-none" />

            <div className="relative z-10 w-full max-w-md">
                <div className="bg-gradient-to-br from-[rgba(10,22,40,0.85)] to-[rgba(15,30,55,0.85)] backdrop-blur-2xl border border-cyan-400/20 rounded-3xl shadow-[0_24px_80px_rgba(0,0,0,0.6),0_0_40px_rgba(0,212,255,0.1)] p-8 sm:p-10 text-center">

                    {/* Logo */}
                    <div className="mb-6">
                        <div className="w-16 h-16 mx-auto rounded-2xl bg-gradient-to-tr from-cyan-400 to-blue-600 flex items-center justify-center shadow-[0_0_25px_rgba(0,212,255,0.5)] mb-4">
                            <Shield className="w-8 h-8 text-white" />
                        </div>
                        <h1 className="text-2xl font-black text-white tracking-wider">A2 Eventos / NZT</h1>
                        <p className="text-[10px] text-gray-400 uppercase tracking-[4px] mt-1 font-semibold">Portal Corporativo</p>
                    </div>

                    {/* Onboarding success banner */}
                    {onboardingSuccess && (
                        <div className="mb-6 p-3 rounded-xl bg-green-500/10 border border-green-500/20 flex items-center gap-3 text-left">
                            <CheckCircle className="w-5 h-5 text-green-400 flex-shrink-0" />
                            <p className="text-sm text-green-300">Senha criada com sucesso! Faça login para acessar o painel.</p>
                        </div>
                    )}

                    {/* Error */}
                    {error && (
                        <div className="mb-6 p-3 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-sm text-left">
                            {error}
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="space-y-5 text-left">
                        {/* Email */}
                        <div>
                            <label className="block text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2">Email de Acesso</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <Mail className="h-5 w-5 text-gray-500" />
                                </div>
                                <input
                                    type="email"
                                    required
                                    autoComplete="email"
                                    value={email}
                                    onChange={e => setEmail(e.target.value)}
                                    placeholder="empresa@exemplo.com"
                                    className="w-full bg-slate-900/80 border border-slate-700 text-white rounded-xl pl-10 p-3 focus:ring-2 focus:ring-cyan-500 focus:border-cyan-500 outline-none transition-all placeholder-gray-600"
                                />
                            </div>
                        </div>

                        {/* Password */}
                        <div>
                            <label className="block text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2">Senha</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <Lock className="h-5 w-5 text-gray-500" />
                                </div>
                                <input
                                    type={showPassword ? 'text' : 'password'}
                                    required
                                    autoComplete="current-password"
                                    minLength={6}
                                    value={password}
                                    onChange={e => setPassword(e.target.value)}
                                    placeholder="••••••••"
                                    className="w-full bg-slate-900/80 border border-slate-700 text-white rounded-xl pl-10 pr-12 p-3 focus:ring-2 focus:ring-cyan-500 focus:border-cyan-500 outline-none transition-all placeholder-gray-600"
                                />
                                <button
                                    type="button"
                                    onClick={() => setShowPassword(!showPassword)}
                                    className="absolute inset-y-0 right-0 pr-3 flex items-center text-gray-500 hover:text-gray-300 transition-colors"
                                >
                                    {showPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
                                </button>
                            </div>
                        </div>

                        {/* Submit */}
                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full mt-2 bg-gradient-to-r from-cyan-600 to-blue-700 hover:from-cyan-500 hover:to-blue-600 text-white font-bold py-3.5 rounded-xl shadow-lg shadow-cyan-500/20 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 tracking-wide"
                        >
                            {loading ? (
                                <><Loader2 className="w-5 h-5 animate-spin" /> AUTENTICANDO...</>
                            ) : (
                                'ENTRAR NO PORTAL'
                            )}
                        </button>
                    </form>

                    <p className="text-[10px] text-gray-600 mt-8 uppercase tracking-widest">
                        &copy; 2026 A2 Eventos &bull; Portal Corporativo B2B
                    </p>
                </div>
            </div>
        </div>
    );
}
